1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single cell with 0 neighbors — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("Rule 1 (Underpopulation): two adjacent cells with 1 neighbor each die — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 (Survival): middle cell of a row of 3 has 2 neighbors and survives — [(0,0),(1,0),(2,0)] result includes (1,0)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("Rule 3 (Overpopulation): center cell of full 3x3 block has 8 neighbors and dies", () => {
19	    const cells: Cell[] = [
20	      [0, 0], [1, 0], [2, 0],
21	      [0, 1], [1, 1], [2, 1],
22	      [0, 2], [1, 2], [2, 2],
23	    ];
24	    const result = nextGeneration(cells);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it.todo("Rule 4 (Reproduction): dead cell with exactly 3 neighbors becomes alive — (1,1) becomes alive from [(0,0),(1,0),(0,1)]");
28	  it.todo("Block still life: 2x2 block stays unchanged — [(0,0),(1,0),(0,1),(1,1)] unchanged");
29	  it.todo("Blinker oscillator: vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
30	  it.todo("should handle negative coordinates correctly");
31	});
32

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (neighborCount: number): boolean =>
12	  neighborCount === 2 || neighborCount === 3;
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const liveCells = new Set(cells.map(cellKey));
16	
17	  const countLiveNeighbors = ([x, y]: Cell): number =>
18	    NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
19	      liveCells.has(cellKey([x + dx, y + dy]))
20	    ).length;
21	
22	  return cells.filter((cell) => survives(countLiveNeighbors(cell)));
23	}
